const { Pool } = require('pg');
require('dotenv').config();

// PostgreSQL接続プールの作成
// RenderのPostgreSQL等ではSSL接続が必須となる場合があるため、ssl設定を有効にします。
// ただし、ローカルのDocker環境ではSSL不要な場合があるため、環境に応じて切り替えます。
const isProduction = process.env.NODE_ENV === 'production';

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: isProduction ? { rejectUnauthorized: false } : false
});

// データベースの初期化（テーブル作成）
const initDb = async () => {
  const createUsersTableQuery = `
    CREATE TABLE IF NOT EXISTS users (
      id SERIAL PRIMARY KEY,
      email VARCHAR(255) UNIQUE NOT NULL,
      password VARCHAR(255) NOT NULL,
      role VARCHAR(50) DEFAULT 'user',
      is_banned BOOLEAN DEFAULT false,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
  `;

  try {
    const client = await pool.connect();
    console.log('データベースに接続しました。初期化処理を開始します...');
    await client.query(createUsersTableQuery);
    console.log('ユーザーテーブルが準備されました。');

    // 管理者ユーザーの初期シードデータを作成（任意）
    // すでに管理者が存在するかチェック
    const checkAdminQuery = `SELECT * FROM users WHERE role = 'admin' LIMIT 1;`;
    const res = await client.query(checkAdminQuery);
    if (res.rows.length === 0) {
      // 初期管理者アカウントを作成 (初期パスワードは admin123)
      // パスワードハッシュ化は別途行うべきですが、起動時にシードとして自動登録します。
      // セキュリティ上、初期パスワードはbcryptでハッシュ化して格納します。
      const bcrypt = require('bcryptjs');
      const hashedPassword = await bcrypt.hash('admin123', 10);

      const insertAdminQuery = `
        INSERT INTO users (email, password, role)
        VALUES ($1, $2, $3)
        ON CONFLICT (email) DO NOTHING;
      `;
      await client.query(insertAdminQuery, ['admin@example.com', hashedPassword, 'admin']);
      console.log('初期管理者アカウント (admin@example.com / admin123) を作成しました。');
    }

    client.release();
  } catch (err) {
    console.error('データベース初期化エラー:', err);
  }
};

module.exports = {
  query: (text, params) => pool.query(text, params),
  pool,
  initDb
};

const jwt = require('jsonwebtoken');
const db = require('../config/db');

// JWT認証とBANステータス確認ミドルウェア
const isAuthenticated = async (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>

  if (!token) {
    return res.status(401).json({ message: '認証トークンが必要です。' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'fallback_secret');

    // トークンに記録されたユーザーIDから最新のユーザー情報を取得し、BANされていないか確認
    const userRes = await db.query('SELECT id, email, role, is_banned FROM users WHERE id = $1', [decoded.id]);

    if (userRes.rows.length === 0) {
      return res.status(404).json({ message: 'ユーザーが見つかりません。' });
    }

    const user = userRes.rows[0];

    if (user.is_banned) {
      return res.status(403).json({ message: 'このアカウントは停止（BAN）されています。' });
    }

    // リクエストオブジェクトにユーザー情報を格納
    req.user = user;
    next();
  } catch (err) {
    console.error('トークン検証エラー:', err);
    return res.status(401).json({ message: 'トークンが無効または有効期限切れです。' });
  }
};

// 特定のロールを要求する認可ミドルウェア
const requireRole = (requiredRole) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ message: '認証が必要です。' });
    }

    if (req.user.role !== requiredRole) {
      return res.status(403).json({ message: 'この操作を実行する権限がありません。' });
    }

    next();
  };
};

module.exports = {
  isAuthenticated,
  requireRole
};

const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const db = require('../config/db');

// サインアップ（新規ユーザー登録）
exports.register = async (req, res) => {
  const { email, password, inviteCode } = req.body;

  if (!email || !password || !inviteCode) {
    return res.status(400).json({ message: 'すべてのフィールドを入力してください。' });
  }

  // 招待コードの検証
  const expectedInviteCode = process.env.REGISTRATION_INVITE_CODE || 'INVITE2026';
  if (inviteCode !== expectedInviteCode) {
    return res.status(400).json({ message: '招待コードが正しくありません。' });
  }

  try {
    // 重複ユーザーの確認
    const userExists = await db.query('SELECT * FROM users WHERE email = $1', [email]);
    if (userExists.rows.length > 0) {
      return res.status(400).json({ message: 'このメールアドレスは既に登録されています。' });
    }

    // パスワードのハッシュ化
    const salt = await bcrypt.genSalt(10);
    const hashedPassword = await bcrypt.hash(password, salt);

    // データベースへの登録
    const newUser = await db.query(
      'INSERT INTO users (email, password, role) VALUES ($1, $2, $3) RETURNING id, email, role, created_at',
      [email, hashedPassword, 'user']
    );

    return res.status(201).json({
      message: 'ユーザーの登録が完了しました。',
      user: newUser.rows[0]
    });
  } catch (err) {
    console.error('サインアップエラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// ログイン
exports.login = async (req, res) => {
  const { email, password } = req.body;

  if (!email || !password) {
    return res.status(400).json({ message: 'メールアドレスとパスワードを入力してください。' });
  }

  try {
    // ユーザーの検索
    const userRes = await db.query('SELECT * FROM users WHERE email = $1', [email]);
    if (userRes.rows.length === 0) {
      return res.status(400).json({ message: 'メールアドレスまたはパスワードが正しくありません。' });
    }

    const user = userRes.rows[0];

    // BAN状態の確認
    if (user.is_banned) {
      return res.status(403).json({ message: 'このアカウントは利用停止（BAN）されています。' });
    }

    // パスワードの照合
    const isMatch = await bcrypt.compare(password, user.password);
    if (!isMatch) {
      return res.status(400).json({ message: 'メールアドレスまたはパスワードが正しくありません。' });
    }

    // JWTトークンの生成
    const token = jwt.sign(
      { id: user.id, email: user.email, role: user.role },
      process.env.JWT_SECRET || 'fallback_secret',
      { expiresIn: '24h' }
    );

    return res.json({
      token,
      user: {
        id: user.id,
        email: user.email,
        role: user.role
      }
    });
  } catch (err) {
    console.error('ログインエラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// ログイン中ユーザー情報の取得
exports.me = async (req, res) => {
  try {
    // authMiddlewareで既にreq.userが設定されている
    return res.json({ user: req.user });
  } catch (err) {
    console.error('ユーザー情報取得エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

const db = require('../config/db');

// ユーザー一覧の取得 (パスワードは除外)
exports.getUsers = async (req, res) => {
  try {
    const result = await db.query(
      'SELECT id, email, role, is_banned, created_at FROM users ORDER BY id ASC'
    );
    return res.json(result.rows);
  } catch (err) {
    console.error('ユーザー一覧取得エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// ユーザーのBAN（アカウント停止）
exports.banUser = async (req, res) => {
  const { id } = req.params;

  // 自分自身をBANするのを防ぐ
  if (parseInt(id) === req.user.id) {
    return res.status(400).json({ message: '自分自身をアカウント停止することはできません。' });
  }

  try {
    const result = await db.query(
      'UPDATE users SET is_banned = true WHERE id = $1 RETURNING id, email, is_banned',
      [id]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ message: 'ユーザーが見つかりません。' });
    }

    return res.json({
      message: 'ユーザーをアカウント停止（BAN）しました。',
      user: result.rows[0]
    });
  } catch (err) {
    console.error('BANエラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// ユーザーのBAN解除
exports.unbanUser = async (req, res) => {
  const { id } = req.params;

  try {
    const result = await db.query(
      'UPDATE users SET is_banned = false WHERE id = $1 RETURNING id, email, is_banned',
      [id]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ message: 'ユーザーが見つかりません。' });
    }

    return res.json({
      message: 'ユーザーのアカウント停止を解除しました。',
      user: result.rows[0]
    });
  } catch (err) {
    console.error('BAN解除エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// ユーザーのロール変更（admin <-> user）
exports.updateUserRole = async (req, res) => {
  const { id } = req.params;
  const { role } = req.body;

  if (role !== 'user' && role !== 'admin') {
    return res.status(400).json({ message: '無効なロールです。user または admin を指定してください。' });
  }

  // 自分自身のロールを変更するのを防ぐ
  if (parseInt(id) === req.user.id) {
    return res.status(400).json({ message: '自分自身の権限を変更することはできません。' });
  }

  try {
    const result = await db.query(
      'UPDATE users SET role = $1 WHERE id = $2 RETURNING id, email, role',
      [role, id]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ message: 'ユーザーが見つかりません。' });
    }

    return res.json({
      message: `ユーザーの権限を ${role} に変更しました。`,
      user: result.rows[0]
    });
  } catch (err) {
    console.error('ロール変更エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

const { Pool } = require('pg');
require('dotenv').config();

const isProduction = process.env.NODE_ENV === 'production';

const pool = new Pool({
  connectionString: process.env.DATABASE_URL,
  ssl: isProduction ? { rejectUnauthorized: false } : false
});

// データベースの初期化（テーブル作成）
const initDb = async () => {
  const createUsersTableQuery = `
    CREATE TABLE IF NOT EXISTS users (
      id SERIAL PRIMARY KEY,
      email VARCHAR(255) UNIQUE NOT NULL,
      password VARCHAR(255) NOT NULL,
      role VARCHAR(50) DEFAULT 'user',
      is_banned BOOLEAN DEFAULT false,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
  `;

  const createTournamentsTableQuery = `
    CREATE TABLE IF NOT EXISTS tournaments (
      id SERIAL PRIMARY KEY,
      name VARCHAR(255) NOT NULL,
      stage VARCHAR(100) NOT NULL,
      winner_team VARCHAR(255) NOT NULL,
      loser_team VARCHAR(255) NOT NULL,
      created_by INTEGER REFERENCES users(id) ON DELETE SET NULL,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
    );
  `;

  try {
    const client = await pool.connect();
    console.log('データベースに接続しました。初期化処理を開始します...');

    // ユーザーテーブル作成
    await client.query(createUsersTableQuery);
    // 大会データテーブル作成
    await client.query(createTournamentsTableQuery);

    console.log('テーブルが準備されました。');

    // 管理者ユーザーの初期シードデータを作成
    const checkAdminQuery = `SELECT * FROM users WHERE role = 'admin' LIMIT 1;`;
    const res = await client.query(checkAdminQuery);
    if (res.rows.length === 0) {
      const bcrypt = require('bcryptjs');
      const hashedPassword = await bcrypt.hash('admin123', 10);

      const insertAdminQuery = `
        INSERT INTO users (email, password, role)
        VALUES ($1, $2, $3)
        ON CONFLICT (email) DO NOTHING;
      `;
      await client.query(insertAdminQuery, ['admin@example.com', hashedPassword, 'admin']);
      console.log('初期管理者アカウント (admin@example.com / admin123) を作成しました。');
    }

    client.release();
  } catch (err) {
    console.error('データベース初期化エラー:', err);
  }
};

module.exports = {
  query: (text, params) => pool.query(text, params),
  pool,
  initDb
};

const db = require('../config/db');

// 大会データと分析結果の取得（一般公開・認証不要）
exports.getTournaments = async (req, res) => {
  try {
    // 全大会データを取得
    const result = await db.query(
      `SELECT t.*, u.email as creator_email 
       FROM tournaments t 
       LEFT JOIN users u ON t.created_by = u.id 
       ORDER BY t.created_at DESC`
    );

    const tournaments = result.rows;

    // 簡単な分析・集計ロジック
    // 各チームの勝利回数をカウント
    const teamStats = {};
    tournaments.forEach(t => {
      // 勝利チームのカウント
      if (t.winner_team) {
        if (!teamStats[t.winner_team]) {
          teamStats[t.winner_team] = { win: 0, lose: 0 };
        }
        teamStats[t.winner_team].win += 1;
      }
      // 敗北チームのカウント
      if (t.loser_team) {
        if (!teamStats[t.loser_team]) {
          teamStats[t.loser_team] = { win: 0, lose: 0 };
        }
        teamStats[t.loser_team].lose += 1;
      }
    });

    // 勝率の計算
    const analytics = Object.keys(teamStats).map(teamName => {
      const stats = teamStats[teamName];
      const totalMatches = stats.win + stats.lose;
      const winRate = totalMatches > 0 ? ((stats.win / totalMatches) * 100).toFixed(1) : 0;
      return {
        team: teamName,
        win: stats.win,
        lose: stats.lose,
        total: totalMatches,
        winRate: parseFloat(winRate)
      };
    }).sort((a, b) => b.winRate - a.winRate || b.total - a.total); // 勝率順、同値は総試合数順

    return res.json({
      tournaments,
      analytics
    });
  } catch (err) {
    console.error('大会データ取得エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

// 大会データの新規登録（認証が必要）
exports.createTournament = async (req, res) => {
  const { name, stage, winner_team, loser_team } = req.body;

  if (!name || !stage || !winner_team || !loser_team) {
    return res.status(400).json({ message: 'すべての必須項目を入力してください。' });
  }

  try {
    const result = await db.query(
      `INSERT INTO tournaments (name, stage, winner_team, loser_team, created_by)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING *`,
      [name, stage, winner_team, loser_team, req.user.id]
    );

    return res.status(201).json({
      message: '大会データを登録しました。',
      tournament: result.rows[0]
    });
  } catch (err) {
    console.error('大会データ登録エラー:', err);
    return res.status(500).json({ message: 'サーバーエラーが発生しました。' });
  }
};

const express = require('express');
const router = express.Router();
const authController = require('../controllers/authController');
const { isAuthenticated } = require('../middleware/authMiddleware');

// 新規ユーザー登録 (招待コード検証あり)
router.post('/register', authController.register);

// ログイン
router.post('/login', authController.login);

// 現在のユーザー情報取得 (認証が必要)
router.get('/me', isAuthenticated, authController.me);

module.exports = router;

const express = require('express');
const router = express.Router();
const adminController = require('../controllers/adminController');
const { isAuthenticated, requireRole } = require('../middleware/authMiddleware');

// 全てのルートで認証と管理者権限が必要
router.use(isAuthenticated);
router.use(requireRole('admin'));

// ユーザー一覧取得
router.get('/users', adminController.getUsers);

// ユーザーのBAN/解除
router.put('/users/:id/ban', adminController.banUser);
router.put('/users/:id/unban', adminController.unbanUser);

// ユーザーのロール変更
router.put('/users/:id/role', adminController.updateUserRole);

module.exports = router;

const express = require('express');
const router = express.Router();
const dashboardController = require('../controllers/dashboardController');
