'use client';

import React, { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';

export const SiteGuard: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const router = useRouter();
  const pathname = usePathname();
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [checking, setChecking] = useState<boolean>(true);

  useEffect(() => {
    const sitePassword = process.env.NEXT_PUBLIC_SITE_PASSWORD;

    // パスワード制限がない場合は無条件でアクセス許可
    if (!sitePassword) {
      setIsAuthorized(true);
      setChecking(false);
      return;
    }

    const isUnlocked = localStorage.getItem('site_unlocked') === sitePassword;

    if (isUnlocked) {
      setIsAuthorized(true);
      if (pathname === '/gate') {
        router.push('/');
      }
    } else {
      setIsAuthorized(false);
      // 解除されておらず、現在地が /gate でない場合は /gate に強制遷移
      if (pathname !== '/gate') {
        router.push('/gate');
      }
    }
    setChecking(false);
  }, [pathname, router]);

  if (checking) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>読み込み中...</p>
      </div>
    );
  }

  // 認証済み、または /gate ページの場合は表示する
  if (isAuthorized || pathname === '/gate') {
    return <>{children}</>;
  }

  // 遷移中のチラつき防止
  return (
    <div className="loading-screen">
      <p>アクセスを制限しています...</p>
    </div>
  );
};

export default SiteGuard;

