import React, { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function GatePage() {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const router = useRouter();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const sitePassword = process.env.NEXT_PUBLIC_SITE_PASSWORD;

    if (!sitePassword) {
      router.push('/');
      return;
    }

    if (password === sitePassword) {
      localStorage.setItem('site_unlocked', password);
      router.push('/');
      // ロードを確実にするためリフレッシュ
      router.refresh();
    } else {
      setError('パスコードが正しくありません。');
    }
  };

  return (
    <div className="gate-wrapper card">
      <div className="gate-icon">🔒</div>
      <h1 className="gate-title">閲覧制限</h1>
      <p className="gate-desc">
        このサイトは現在、関係者向けのテスト公開中です。閲覧するにはパスコードを入力してください。
      </p>

      {error && <div className="error-msg">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label className="form-label" htmlFor="passcode">
            パスコード
          </label>
          <input
            id="passcode"
            type="password"
            className="form-input"
            placeholder="パスコードを入力"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>
        <button type="submit" className="submit-btn">
          ロック解除
        </button>
      </form>
    </div>
  );
}

