'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '../../context/AuthContext';

interface User {
  id: number;
  email: string;
  role: string;
  is_banned: boolean;
  created_at: string;
}

export default function AdminPage() {
  const { user: currentUser, token, isLoading, apiFetch } = useAuth();
  const router = useRouter();

  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // 認証と管理者権限のガード
  useEffect(() => {
    if (!isLoading) {
      if (!token) {
        router.push('/secret-login');
      } else if (currentUser?.role !== 'admin') {
        alert('管理者権限が必要です。');
        router.push('/');
      } else {
        fetchUsers();
      }
    }
  }, [isLoading, token, currentUser, router]);

  const fetchUsers = async () => {
    setLoading(true);
    const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
    try {
      const response = await apiFetch(`${apiUrl}/api/admin/users`);
      if (!response.ok) {
        throw new Error('ユーザー一覧の取得に失敗しました。');
      }
      const data = await response.json();
      setUsers(data);
    } catch (err: any) {
      setError(err.message || '通信エラーが発生しました。');
    } finally {
      setLoading(false);
    }
  };

  const handleBanToggle = async (userId: number, isBanned: boolean) => {
    setError('');
    setMessage('');
    const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
    const action = isBanned ? 'unban' : 'ban';

    try {
      const response = await apiFetch(`${apiUrl}/api/admin/users/${userId}/${action}`, {
        method: 'PUT',
      });
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || '操作に失敗しました。');
      }

      setMessage(data.message);
      fetchUsers(); // 一覧の更新
    } catch (err: any) {
      setError(err.message || 'エラーが発生しました。');
    }
  };

  const handleRoleToggle = async (userId: number, currentRole: string) => {
    setError('');
    setMessage('');
    const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';
    const newRole = currentRole === 'admin' ? 'user' : 'admin';

    if (!window.confirm(`権限を ${newRole} に変更してもよろしいですか？`)) {
      return;
    }

    try {
      const response = await apiFetch(`${apiUrl}/api/admin/users/${userId}/role`, {
        method: 'PUT',
        body: JSON.stringify({ role: newRole }),
      });
      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || '権限変更に失敗しました。');
      }

      setMessage(data.message);
      fetchUsers(); // 一覧の更新
    } catch (err: any) {
      setError(err.message || 'エラーが発生しました。');
    }
  };

  if (isLoading || loading) {
    return (
      <div className="loading-screen" style={{ height: '50vh' }}>
        <div className="spinner"></div>
        <p>ユーザーデータをロード中...</p>
      </div>
