### 1. 閲覧制限ゲート画面 (パスコード入力画面)
**ファイルパス**: `frontend/src/app/gate/page.tsx`
環境変数 `NEXT_PUBLIC_SITE_PASSWORD` と入力されたパスコードを照合し、一致した場合は `localStorage` にロック解除キーを保存してダッシュボード（`/`）へ遷移します。

```typescript
'use client';

import React, { useState } from 'react';
import { useRouter } from 'next/navigation';

export default function GatePage() {
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const router = useRouter();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const sitePassword = process.env.NEXT_PUBLIC_SITE_PASSWORD;

    // 環境変数にパスコード制限が設定されていない場合は、ダッシュボードへ遷移
    if (!sitePassword) {
      router.push('/');
      return;
    }

    if (password === sitePassword) {
      localStorage.setItem('site_unlocked', password);
      router.push('/');
      // ロック解除状態を反映するためにリフレッシュ
      router.refresh();
    } else {
      setError('パスコードが正しくありません。');
    }
  };

  return (
    <div className="gate-wrapper card">
      <div className="gate-icon">🔒</div>
      <h1 className="gate-title">閲覧制限</h1>
      <p className="gate-desc">
        このサイトは現在、関係者向けのテスト公開中です。閲覧するにはパスコードを入力してください。
      </p>

      {error && <div className="error-msg">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label className="form-label" htmlFor="passcode">
            パスコード
          </label>
          <input
            id="passcode"
            type="password"
            className="form-input"
            placeholder="パスコードを入力"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>
        <button type="submit" className="submit-btn">
          ロック解除
        </button>
      </form>
    </div>
  );
}
```

