import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  // サーバー起動時の実行時環境変数 SITE_PASSWORD を取得（ビルド時に固定値化されない）
  const sitePassword = process.env.SITE_PASSWORD;
  const { pathname } = request.nextUrl;

  // 1. パスコードが設定されていない場合はアクセス制限を適用しない
  if (!sitePassword) {
    return NextResponse.next();
  }

  // 2. /gate 自体、APIルート、および静的アセット（画像やJS等）は無限ループを防ぐためスルーする
  if (
    pathname.startsWith('/gate') ||
    pathname.startsWith('/api') ||
    pathname.startsWith('/_next') ||
    pathname.includes('.')
  ) {
    return NextResponse.next();
  }

  // 3. Cookieに保存された解除パスコードを取得
  const unlocked = request.cookies.get('site_unlocked')?.value;

  // 4. パスコードが環境変数と一致しているか検証
  if (unlocked === sitePassword) {
    return NextResponse.next();
  }

  // 5. 未解除の場合は、/gate ページへリダイレクト
  const url = request.nextUrl.clone();
  url.pathname = '/gate';
  return NextResponse.redirect(url);
}

// ミドルウェアを適用するパスを設定
export const config = {
  matcher: '/((?!api|_next/static|_next/image|favicon.ico).*)',
};

import { NextRequest, NextResponse } from 'next/server';

export async function POST(request: NextRequest) {
  try {
    const { password } = await request.json();
    const sitePassword = process.env.SITE_PASSWORD;

    if (!sitePassword) {
      return NextResponse.json(
        { message: 'パスコード制限は無効になっています。' },
        { status: 400 }
      );
    }

    if (password === sitePassword) {
      const response = NextResponse.json({ success: true });

      // クッキーをセット。セキュリティ向上のため httpOnly 属性と適切な有効期限を設定
      response.cookies.set('site_unlocked', password, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        path: '/',
        maxAge: 60 * 60 * 24 * 7, // 1週間有効
      });

      return response;
    }

    return NextResponse.json(
      { message: 'パスコードが正しくありません。' },
      { status: 400 }
    );
  } catch (error) {
    console.error('パスコード検証エラー:', error);
    return NextResponse.json(
      { message: 'サーバーエラーが発生しました。' },
      { status: 500 }
    );
  }
}

