import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';

export async function POST(request: NextRequest) {
  try {
    // リクエストボディをプレーンテキストとして取得し、安全にパースする
    const text = await request.text();
    if (!text) {
      return NextResponse.json(
        { message: 'リクエストボディが空です。' },
        { status: 400 }
      );
    }

    let password = '';
    try {
      const body = JSON.parse(text);
      password = body.password;
    } catch (e) {
      return NextResponse.json(
        { message: 'JSONの形式が正しくありません。' },
        { status: 400 }
      );
    }

    const sitePassword = process.env.SITE_PASSWORD;

    if (!sitePassword) {
      return NextResponse.json(
        { message: 'パスコード制限は無効になっています。' },
        { status: 400 }
      );
    }

    if (password === sitePassword) {
      // Next.js標準の cookies() ヘルパーを使用してクッキーを安全にセット
      cookies().set('site_unlocked', password, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        path: '/',
        maxAge: 60 * 60 * 24 * 7, // 1週間有効
      });

      return NextResponse.json({ success: true });
    }

    return NextResponse.json(
      { message: 'パスコードが正しくありません。' },
      { status: 400 }
    );
  } catch (error: any) {
    console.error('パスコード検証APIエラー:', error);
    return NextResponse.json(
      { message: 'サーバーエラーが発生しました。', error: error.message },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  try {
    const sitePassword = process.env.SITE_PASSWORD;
    const { pathname } = request.nextUrl;

    // 1. パスコードが設定されていない場合はスルー（一般公開）
    if (!sitePassword) {
      return NextResponse.next();
    }

    // 2. /gate 自身、APIルート、および画像やJS等のアセットは無限ループ防止のためスルー
    if (
      pathname.startsWith('/gate') ||
      pathname.startsWith('/api') ||
      pathname.startsWith('/_next') ||
      pathname.includes('.')
    ) {
      return NextResponse.next();
    }

    // 3. Cookieに保存された解除パスコードを取得
    const cookieObj = request.cookies.get('site_unlocked');

    // Next.jsのバージョン互換性対応（オブジェクトか文字列かを判定して安全に値を抽出）
    const unlocked = cookieObj && typeof cookieObj === 'object' && 'value' in cookieObj
      ? (cookieObj as any).value
      : cookieObj;

    // 4. パスコードが環境変数と一致している場合はそのまま通す
    if (unlocked === sitePassword) {
      return NextResponse.next();
    }

    // 5. 未解除の場合は、/gate ページへリダイレクト
    const url = request.nextUrl.clone();
    url.pathname = '/gate';
    return NextResponse.redirect(url);
  } catch (error) {
    // ミドルウェア内部での例外発生によりサイト全体が「Internal Server Error」でクラッシュするのを防ぐ
    console.error('ミドルウェア実行エラー:', error);
    return NextResponse.next();
  }
}

// ミドルウェアを適用するパスを設定
export const config = {
  matcher: '/((?!api|_next/static|_next/image|favicon.ico).*)',
};

import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';

export async function POST(request: NextRequest) {
  try {
    const text = await request.text();
    if (!text) {
      return NextResponse.json(
        { message: 'リクエストボディが空です。' },
        { status: 400 }
      );
    }

    let password = '';
    try {
      const body = JSON.parse(text);
      password = body.password;
    } catch (e) {
      return NextResponse.json(
        { message: 'JSONの形式が正しくありません。' },
        { status: 400 }
      );
    }

    const sitePassword = process.env.SITE_PASSWORD;

    if (!sitePassword) {
      return NextResponse.json(
        { message: 'パスコード制限は無効になっています。' },
        { status: 400 }
      );
    }

    if (password === sitePassword) {
      // cookies() を await することで、Next.js 15 の非同期化に対応しつつ、14以前のバージョンでも動作させます。
      const cookieStore = await cookies();
      cookieStore.set('site_unlocked', password, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        path: '/',
        maxAge: 60 * 60 * 24 * 7, // 1週間有効
      });

      return NextResponse.json({ success: true });
    }

    return NextResponse.json(
      { message: 'パスコードが正しくありません。' },
      { status: 400 }
    );
  } catch (error: any) {
    console.error('パスコード検証APIエラー:', error);
    return NextResponse.json(
      { message: 'サーバーエラーが発生しました。', error: error.message },
      { status: 500 }
    );
  }
}

