'use client';

import React, { createContext, useState, useEffect, useContext } from 'react';
import { useRouter } from 'next/navigation';

interface User {
  id: number;
  email: string;
  role: string;
}

interface AuthContextType {
  user: User | null;
  token: string | null;
  isLoading: boolean;
  login: (token: string, user: User) => void;
  logout: () => void;
  apiFetch: (url: string, options?: RequestInit) => Promise<Response>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const parseJwt = (token: string): any => {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch (e) {
    return null;
  }
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const router = useRouter();

  useEffect(() => {
    const storedToken = localStorage.getItem('token');
    const storedUser = localStorage.getItem('user');

    if (storedToken && storedUser) {
      const decoded = parseJwt(storedToken);
      if (decoded && decoded.exp * 1000 > Date.now()) {
        setToken(storedToken);
        setUser(JSON.parse(storedUser));
      } else {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        document.cookie = 'token=; path=/; max-age=0';
        document.cookie = 'role=; path=/; max-age=0';
      }
    }
    setIsLoading(false);
  }, []);

  const login = (newToken: string, newUser: User) => {
    setToken(newToken);
    setUser(newUser);
    localStorage.setItem('token', newToken);
    localStorage.setItem('user', JSON.stringify(newUser));

    // ミドルウェア（サーバーサイド）で判定できるようにCookieにもセット
    document.cookie = `token=${newToken}; path=/; max-age=${60 * 60 * 24 * 7}; SameSite=Lax`;
    document.cookie = `role=${newUser.role}; path=/; max-age=${60 * 60 * 24 * 7}; SameSite=Lax`;
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');

    // Cookieもクリア
    document.cookie = 'token=; path=/; max-age=0';
    document.cookie = 'role=; path=/; max-age=0';
    router.push('/');
  };

  const apiFetch = async (url: string, options: RequestInit = {}) => {
    const headers = new Headers(options.headers || {});

    if (token) {
      headers.set('Authorization', `Bearer ${token}`);
    }

    if (!headers.has('Content-Type') && !(options.body instanceof FormData)) {
      headers.set('Content-Type', 'application/json');
    }

    const response = await fetch(url, {
      ...options,
      headers
    });

    if (response.status === 403) {
      const data = await response.clone().json().catch(() => ({}));
      if (data.detail && data.detail.includes('BAN')) {
        alert('アカウントが利用停止されたため、ログアウトします。');
        logout();
      }
    }

    return response;
  };

  return (
    <AuthContext.Provider value={{ user, token, isLoading, login, logout, apiFetch }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
export default AuthProvider;

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
  try {
    const sitePassword = process.env.SITE_PASSWORD;
    const { pathname } = request.nextUrl;

    // --- 1. テスト公開用簡易パスコードロックの処理 ---
    if (sitePassword) {
      if (
        !pathname.startsWith('/gate') &&
        !pathname.startsWith('/api') &&
        !pathname.startsWith('/_next') &&
        !pathname.includes('.')
      ) {
        const cookieObj = request.cookies.get('site_unlocked');
        const unlocked = cookieObj && typeof cookieObj === 'object' && 'value' in cookieObj
          ? (cookieObj as any).value
          : cookieObj;

        if (unlocked !== sitePassword) {
          const url = request.nextUrl.clone();
          url.pathname = '/gate';
          return NextResponse.redirect(url);
        }
      }
    }

    // --- 2. 大会データ登録・編集画面（/tournament/[id]）のスタッフ認証チェック ---
    // 例: /tournament/1 や /tournament/123 など（配下に /dashboard や /player が続かないもの）
    const tournamentRegPattern = /^\/tournament\/[0-9]+$/;
    if (tournamentRegPattern.test(pathname)) {
      const tokenObj = request.cookies.get('token');
      const token = tokenObj && typeof tokenObj === 'object' && 'value' in tokenObj
        ? (tokenObj as any).value
        : tokenObj;

      if (!token) {
        const url = request.nextUrl.clone();
        url.pathname = '/secret-login';
        url.searchParams.set('redirect', pathname);
        return NextResponse.redirect(url);
      }
    }

    // --- 3. 管理者専用画面（/admin）の管理者認証チェック ---
    if (pathname.startsWith('/admin')) {
      const tokenObj = request.cookies.get('token');
      const token = tokenObj && typeof tokenObj === 'object' && 'value' in tokenObj
        ? (tokenObj as any).value
        : tokenObj;
      const roleObj = request.cookies.get('role');
      const role = roleObj && typeof roleObj === 'object' && 'value' in roleObj
        ? (roleObj as any).value
        : roleObj;

      if (!token || role !== 'admin') {
        const url = request.nextUrl.clone();
        url.pathname = '/secret-login';
        return NextResponse.redirect(url);
      }
    }

    return NextResponse.next();
  } catch (error) {
    console.error('ミドルウェア実行エラー:', error);
    return NextResponse.next();
  }
}

