import sqlite3
import os
import json

db_paths = ["temp_history.db", "temp_current.db"]

for db_path in db_paths:
    if not os.path.exists(db_path):
        continue
    print(f"\n========================================\nDATABASE: {db_path}\n========================================")

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    try:
        cursor.execute("SELECT COUNT(*) FROM steps;")
        total_steps = cursor.fetchone()[0]
        print(f"Total steps in DB: {total_steps}")

        search_words = ["postgres", "sqlite", "nikke_arena.db", "volume", "tournament", "database", "移行", "復元"]

        # 各キーワードで検索
        for word in search_words:
            cursor.execute("SELECT idx, step_type, step_payload FROM steps WHERE step_payload LIKE ? ORDER BY idx DESC LIMIT 8;", (f"%{word}%",))
            rows = cursor.fetchall()
            if rows:
                print(f"\nMatches for '{word}':")
                for r in rows:
                    idx, step_type, payload = r
                    payload_snippet = ""
                    try:
                        # payloadはJSON形式
                        js = json.loads(payload)
                        # JSONをパースして中身を調査
                        if "userInput" in js:
                            payload_snippet = "[User] " + str(js["userInput"].get("text", ""))
                        elif "plannerResponse" in js:
                            payload_snippet = "[Model] " + str(js["plannerResponse"].get("text", ""))
                        elif "systemMessage" in js:
                            payload_snippet = "[System] " + str(js["systemMessage"].get("text", ""))
                        elif "stepOutcome" in js:
                            # 実行したツールや結果
                            outcome = js["stepOutcome"]
                            if "toolResults" in outcome:
                                for tr in outcome["toolResults"]:
                                    if "runCommandResult" in tr:
                                        payload_snippet = f"[Cmd] {tr['runCommandResult'].get('command', '')} -> {tr['runCommandResult'].get('stdout', '')[:100]}"
                                        break
                                    elif "writeFileResult" in tr:
                                        payload_snippet = f"[Write] {tr['writeFileResult'].get('filePath', '')}"
                                        break
                            if not payload_snippet:
                                payload_snippet = "[Outcome] " + str(outcome)[:150]
                        else:
                            payload_snippet = str(js)[:200]
                    except Exception:
                        payload_snippet = str(payload)

                    if len(payload_snippet) > 200:
                        payload_snippet = payload_snippet[:200] + "..."
                    print(f"  Step {idx} ({step_type}): {payload_snippet}")

    except Exception as e:
        print(f"Error querying: {e}")
    finally:
        conn.close()

import sqlite3
import os
import re

db_paths = ["temp_history.db", "temp_current.db"]

# Printable ASCII + Japanese characters regex
pattern = re.compile(b'[\x20-\x7E\xE3\x81-\x83\xE4-\xE9\x80-\xBF]{8,}')

keywords = [b'sqlite', b'nikke', b'volume', b'db', b'postgres', b'migrate', b'data', b'tournaments']

for db_path in db_paths:
    if not os.path.exists(db_path):
        continue
    print(f"\n========================================\nDATABASE: {db_path}\n========================================")

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    try:
        cursor.execute("SELECT idx, step_payload FROM steps ORDER BY idx DESC;")
        rows = cursor.fetchall()
        print(f"Total steps to scan: {len(rows)}")

        match_count = 0
        for idx, payload in rows:
            if not isinstance(payload, bytes):
                continue

            # キーワードが含まれているか大雑把にチェック
            has_keyword = False
            for kw in keywords:
                if kw in payload.lower():
                    has_keyword = True
                    break

            if not has_keyword:
                continue

            # payload から正規表現で printable 文字列を抽出
            matches = pattern.findall(payload)
            printed_header = False
            for m in matches:
                try:
                    # UTF-8デコードを試みる
                    text = m.decode('utf-8', errors='ignore').strip()
                    # デコード後のテキストにキーワードが含まれているか
                    lower_text = text.lower()
                    kw_found = []
                    for kw in keywords:
                        if kw.decode('utf-8') in lower_text:
                            kw_found.append(kw.decode('utf-8'))

                    if kw_found and len(text) > 10:
                        if not printed_header:
                            print(f"\n--- Step {idx} Match (Keywords: {', '.join(kw_found)}) ---")
                            printed_header = True
                        print(f"  {text[:150]}")
                        if len(text) > 150:
                            print(f"  ... {text[150:300]}")
                        match_count += 1
                except Exception:
                    pass

            if match_count > 30:
                print("Limit reached for matches. Stopping scan for this DB.")
                break

    except Exception as e:
        print(f"Error querying: {e}")
    finally:
        conn.close()

