// 大会リストの初回取得と選択状態の初期化
useEffect(() => {
  if (isFirstLoad) return;
  const fetchTournaments = async () => {
    try {
      const res = await fetch(`/api/tournaments?t=${Date.now()}`, { cache: 'no-store' });
      const data: any[] = await res.json();
      setAllTournaments(data);

      if (data.length > 0) {
        const latest = data[data.length - 1];
        const initialSeason = latest.season || "β30";
        setFilterSeasons([initialSeason]);
        // デフォルトでは Owner フィルタは空（全て選択扱い）とするか、最新の owner にするか
        // ニーズ的には season で絞って、全ての owner を見ることが多いと想定
        setFilterOwners([]);
      } else {
        // 大会データが0件のとき、ローディングを終了する
        setLoading(false);
      }
    } catch (e) {
      console.error(e);
      // エラー時もローディングを終了する
      setLoading(false);
    }
  };
  fetchTournaments();
}, [isFirstLoad]);

