"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { ChevronLeft, ShieldAlert, ShieldCheck, UserX, UserCheck, RefreshCw, Crown, Users } from "lucide-react";

interface AppUser {
  id: number;
  email: string;
  role: "contributor" | "admin";
  is_banned: boolean;
  created_at: string;
}

export default function AdminUsersPage() {
  const router = useRouter();
  const [currentUser, setCurrentUser] = useState<AppUser | null>(null);
  const [authChecked, setAuthChecked] = useState(false);
  const [users, setUsers] = useState<AppUser[]>([]);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState<{ text: string; ok: boolean } | null>(null);

  const showMsg = (text: string, ok: boolean) => {
    setMessage({ text, ok });
    setTimeout(() => setMessage(null), 4000);
  };

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/auth/users", { credentials: "include" });
      if (!res.ok) return;
      setUsers(await res.json());
    } finally {
      setLoading(false);
    }
  };

  // 認証チェック: admin のみ
  useEffect(() => {
    fetch("/api/auth/me", { credentials: "include" })
      .then((res) => res.ok ? res.json() : null)
      .then((user) => {
        if (!user || user.role !== "admin") {
          router.replace("/secret-login");
        } else {
          setCurrentUser(user);
          setAuthChecked(true);
          fetchUsers();
        }
      })
      .catch(() => router.replace("/secret-login"));
  }, []);

  const handleBan = async (userId: number, ban: boolean) => {
    const action = ban ? "ban" : "unban";
    const res = await fetch(`/api/auth/users/${userId}/${action}`, {
      method: "PUT",
      credentials: "include",
    });
    if (res.ok) {
      showMsg(ban ? "BANしました" : "BAN解除しました", true);
      fetchUsers();
    } else {
      const data = await res.json().catch(() => ({}));
      showMsg(data.detail || "操作に失敗しました", false);
    }
  };

  const handleRoleChange = async (userId: number, newRole: string) => {
    const res = await fetch(`/api/auth/users/${userId}/role`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ role: newRole }),
      credentials: "include",
    });
    if (res.ok) {
      showMsg(`ロールを「${newRole}」に変更しました`, true);
      fetchUsers();
    } else {
      const data = await res.json().catch(() => ({}));
      showMsg(data.detail || "変更に失敗しました", false);
    }
  };

  if (!authChecked) {
    return (
      <div className="min-h-screen bg-[#0a0f1e] flex items-center justify-center">
        <div className="animate-spin w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full" />
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-[#0a0f1e] text-slate-100 p-4 md:p-8">
      <div className="max-w-4xl mx-auto">
        {/* ヘッダー */}
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center space-x-4">
            <Link href="/admin" className="p-2 bg-white/5 hover:bg-white/10 rounded-xl text-slate-400 hover:text-white transition-all">
              <ChevronLeft size={20} />
            </Link>
            <div>
              <div className="flex items-center space-x-2 mb-1">
                <Users size={20} className="text-purple-400" />
                <span className="text-xs font-bold text-purple-400 uppercase tracking-widest">Admin</span>
              </div>
              <h1 className="text-2xl font-black text-white">ユーザー管理</h1>
              <p className="text-slate-400 text-sm mt-1">登録ユーザーの権限管理・BAN操作</p>
            </div>
          </div>
          <button
            onClick={fetchUsers}
            className="flex items-center space-x-2 px-4 py-2 bg-white/5 hover:bg-white/10 rounded-xl text-slate-400 hover:text-white transition-all"
          >
            <RefreshCw size={16} className={loading ? "animate-spin" : ""} />
            <span className="text-sm font-bold">再読み込み</span>
          </button>
        </div>

        {/* メッセージ */}
        {message && (
          <div className={`mb-6 p-4 rounded-xl font-bold text-sm ${message.ok ? "bg-emerald-500/10 text-emerald-400 ring-1 ring-emerald-500/30" : "bg-red-500/10 text-red-400 ring-1 ring-red-500/30"}`}>
            {message.text}
          </div>
        )}

        {/* 統計 */}
        <div className="grid grid-cols-3 gap-4 mb-6">
          <div className="bg-slate-800/50 p-4 rounded-2xl ring-1 ring-white/10">
            <p className="text-slate-400 text-xs font-bold mb-1">全ユーザー</p>
            <p className="text-3xl font-black text-slate-100">{users.length}</p>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-2xl ring-1 ring-white/10">
            <p className="text-slate-400 text-xs font-bold mb-1">管理者</p>
            <p className="text-3xl font-black text-amber-400">{users.filter(u => u.role === "admin").length}</p>
          </div>
          <div className="bg-slate-800/50 p-4 rounded-2xl ring-1 ring-white/10">
            <p className="text-slate-400 text-xs font-bold mb-1">BAN中</p>
            <p className="text-3xl font-black text-red-400">{users.filter(u => u.is_banned).length}</p>
          </div>
        </div>

        {/* ユーザー一覧 */}
        <div className="bg-slate-900/50 rounded-2xl ring-1 ring-white/10 overflow-hidden">
          <div className="bg-slate-800/80 px-6 py-4 border-b border-white/10">
            <h2 className="font-bold text-white">登録ユーザー一覧</h2>
          </div>
          {loading ? (
            <div className="p-12 text-center text-slate-500">読み込み中...</div>
          ) : users.length === 0 ? (
            <div className="p-12 text-center text-slate-500">ユーザーが登録されていません</div>
          ) : (
            <div className="divide-y divide-white/5">
              {users.map((u) => (
                <div key={u.id} className={`flex items-center justify-between p-5 ${u.is_banned ? "bg-red-500/5" : "hover:bg-white/3"} transition-colors`}>
                  <div className="flex items-center space-x-4">
                    {/* アバター */}
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-sm font-black ${
                      u.is_banned ? "bg-red-500/20 text-red-400" :
                      u.role === "admin" ? "bg-amber-500/20 text-amber-400" :
                      "bg-blue-500/20 text-blue-400"
                    }`}>
                      {u.email[0].toUpperCase()}
                    </div>
                    <div>
                      <div className="flex items-center space-x-2">
                        <span className={`font-bold ${u.is_banned ? "text-red-400 line-through" : "text-white"}`}>
                          {u.email}
                        </span>
                        {u.id === currentUser?.id && (
                          <span className="text-[10px] bg-blue-500/20 text-blue-400 px-2 py-0.5 rounded-full font-bold">あなた</span>
                        )}
                        {u.is_banned && (
                          <span className="text-[10px] bg-red-500/20 text-red-400 px-2 py-0.5 rounded-full font-bold">BAN中</span>
                        )}
                      </div>
                      <div className="flex items-center space-x-2 mt-0.5">
                        <span className={`text-xs font-bold ${u.role === "admin" ? "text-amber-400" : "text-slate-500"}`}>
                          {u.role === "admin" ? "🔑 管理者" : "📋 情報提供者"}
                        </span>
                        <span className="text-xs text-slate-600">
                          登録: {new Date(u.created_at).toLocaleDateString("ja-JP")}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* 操作ボタン（自分自身には操作不可） */}
                  {u.id !== currentUser?.id && (
                    <div className="flex items-center space-x-2">
                      {/* ロール変更 */}
                      {u.role === "contributor" ? (
                        <button
                          onClick={() => { if (confirm(`「${u.email}」を管理者に昇格しますか？`)) handleRoleChange(u.id, "admin"); }}
                          className="flex items-center space-x-1 px-3 py-1.5 bg-amber-500/10 hover:bg-amber-500/20 text-amber-400 rounded-lg text-xs font-bold transition-all ring-1 ring-amber-500/20"
                        >
                          <Crown size={12} />
                          <span>管理者に昇格</span>
                        </button>
                      ) : (
                        <button
                          onClick={() => { if (confirm(`「${u.email}」を情報提供者に降格しますか？`)) handleRoleChange(u.id, "contributor"); }}
                          className="flex items-center space-x-1 px-3 py-1.5 bg-slate-500/10 hover:bg-slate-500/20 text-slate-400 rounded-lg text-xs font-bold transition-all ring-1 ring-slate-500/20"
                        >
                          <ShieldAlert size={12} />
                          <span>提供者に降格</span>
                        </button>
                      )}
                      {/* BAN/解除 */}
                      {u.is_banned ? (
                        <button
                          onClick={() => { if (confirm(`「${u.email}」のBANを解除しますか？`)) handleBan(u.id, false); }}
                          className="flex items-center space-x-1 px-3 py-1.5 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 rounded-lg text-xs font-bold transition-all ring-1 ring-emerald-500/20"
                        >
                          <UserCheck size={12} />
                          <span>BAN解除</span>
                        </button>
                      ) : (
                        <button
                          onClick={() => { if (confirm(`「${u.email}」をBANしますか？`)) handleBan(u.id, true); }}
                          className="flex items-center space-x-1 px-3 py-1.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg text-xs font-bold transition-all ring-1 ring-red-500/20"
                        >
                          <UserX size={12} />
                          <span>BAN</span>
                        </button>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </main>
  );
}
